import './give.css';

export default function Give() {
  return (
    <>
    <div>
        <button>
          <a 
            type="submit" 
            className="giveButton"
            href='https://adventistgiving.org/donate/ANIM2I'
          >
          Give Now
          </a>
        </button>
    </div>
    </>
  )
}
